// modules/stripe/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'stripe',
  description: 'Handles Stripe integration for subscription management.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/stripe/subscribe', auth: true },
    ],
    functions: [],
    types: [],
  },

  sideEffects: [
    'writes to: subscriptions table',
  ],

  invariants: [
    'A subscription must always be bound to exactly one user',
  ],
});

// modules/stripe/handlers/subscribe.ts
import { Request, Response } from 'bun';
import { requireUser } from '/lib/auth';
import { query } from '/lib/db';
import { Result, ok, err } from '/lib/result';

export async function subscribe(req: Request): Promise<Response> {
  const user = await requireUser(req);
  if (!user) return err({ code: 'UNAUTHORIZED', message: 'User not authenticated' });

  try {
    // Assume we have a function to create a Stripe subscription
    const stripeSubscriptionId = await createStripeSubscription(user.id);

    // Store the subscription ID in the database
    await query('INSERT INTO subscriptions (user_id, stripe_subscription_id) VALUES ($1, $2)', [user.id, stripeSubscriptionId]);

    return ok({ message: 'Subscription created successfully', stripeSubscriptionId });
  } catch (error) {
    console.error('Error creating Stripe subscription:', error);
    return err({ code: 'INTERNAL_ERROR', message: 'Failed to create subscription' });
  }
}

